update pm_trial_assess
set approval_date              = #{updateTime,jdbcType=TIMESTAMP},
    approval_result            = #{approvalResult,jdbcType=VARCHAR},
    update_time                = #{updateTime,jdbcType=TIMESTAMP},
    update_by                  = #{updateBy,jdbcType=BIGINT}
where id = #{id,jdbcType=BIGINT}


update pm_trial_assess
set current_node          = #{currentNode,jdbcType=VARCHAR},
    eligible_file      = #{eligibleFile,jdbcType=BIT},
    update_time        = #{updateTime,jdbcType=TIMESTAMP},
    update_by          = #{updateBy,jdbcType=BIGINT}
where id = #{id,jdbcType=BIGINT}
